/**
 * 婵犵數濮烽弫鎼佸磻閻愬搫鍨傞柛顐ｆ礀缁犱即鏌熼梻瀵割槮缂佺姾顫夐妵鍕箛閳轰胶浼勯梺鍝勬４缁犳捇寮婚敐澶婃闁圭瀛╅崰鎰版⒑瀹曞洨甯涙慨濠傜秺婵＄敻宕熼鍓ф澑闂佽宕樺▍鏇炩枔婵犳碍鈷戠紓浣诡焽閳洟鏌熼悷鐗堝枠鐎殿喛顕ч埥澶娢熼柨瀣澑闂備礁鎲℃笟妤呭窗濮樿泛围闁哄顑欏〒濠氭煏閸繃顥為悘蹇ｅ弮閺岀喖鎳為妷褏鐓傞梺?embedding 濠电姴鐥夐弶搴撳亾濡や焦鍙忛柣鎴ｆ绾惧鏌ｅΟ娆惧殭闁哄嫨鍎甸弻鈥愁吋鎼粹€茬爱闂佺顑嗛幑鍥х暦瑜版帩鏁冮柨婵嗗€圭€氳崵绱撻崒娆戭槮妞ゆ垵鎳橀弫鍐敂閸曨厽娈鹃梺闈浥堥弲鈺呭极閸ヮ剚鐓熼柟瀛樼箖椤ユ粍绻涢崼顐㈠籍婵?DB
 * 闂傚倸鍊搁崐椋庣矆娓氣偓楠炲鏁嶉崟顐ｇ€抽悗骞垮劚椤︻垶宕归崒鐐寸厱鐟滃酣銆冮崨瀛樷拻妞ゆ牗绋撶粻鍓р偓鐟板閸犳洜鑺遍懡銈囩＜闁逞屽墮閻ｆ繈宕熼鍌氬箰闁诲氦顫夐幖鈺呭窗閺嶎厼鐤い鏍仜濮规煡鏌曟径鍡樻珕闁?= nameEn + shortDescriptionEn + detailsEn闂傚倸鍊搁崐鐑芥倿閿旈敮鍋撶粭娑樻噽閻瑩鏌熸潏楣冩闁稿顑夐弻娑㈠焺閸忊晜鍨甸埢?000闂傚倸鍊峰ù鍥敋瑜忛埀顒佺▓閺呮繄鍒掑▎鎾崇婵＄偛鐨烽崑鎾诲礃椤旇偐鐤€濡炪倖姊婚悺鏂款焽? */
export async function computeAndStoreProductEmbedding(productId: number): Promise<void> {
  const db = getDb();
  const [product] = await db
    .select({
      id: products.id,
      nameEn: products.nameEn,
      nameZh: products.nameZh,
      shortDescriptionEn: products.shortDescriptionEn,
      detailsEn: products.detailsEn,
    })
    .from(products)
    .where(eq(products.id, productId))
    .limit(1);

  if (!product) return;

  const fullText = [
    product.nameEn ?? product.nameZh,
    product.shortDescriptionEn ?? "",
    (product.detailsEn ?? "").slice(0, 1500),
  ]
    .filter(Boolean)
    .join("\n");

  const embedding = await getEmbedding(fullText);

  await db
    .update(products)
    .set({
      embeddingJson: embedding,
      embeddingUpdatedAt: new Date(),
      updatedAt: new Date(),
    })
    .where(eq(products.id, productId));
}

